import { createClient } from '@/utils/supabase/server'
import { redirect } from 'next/navigation'
import { DateRangeFilter } from '@/components/shared/date-range-filter'
import { applyDateFilter } from '@/lib/date-filter'
import { Card } from '@/components/Card'
import Link from 'next/link'
import { ShoppingCart, CheckCircle2, Clock, XCircle, PackageOpen } from 'lucide-react'

export default async function VendorOrdersPage(props: { searchParams: Promise<any> }) {
  const searchParams = await props.searchParams;
  const supabase = await createClient()

  const { data: { user } } = await supabase.auth.getUser()
  if (process.env.DEVELOPMENT_MODE !== 'true' && !user) redirect('/login')

  const { data: vendorUser } = await applyDateFilter(supabase.from('vendor_users').select('vendor_id, vendors(id, status)'), searchParams).eq('user_id', (user?.id || '')).single();
  const vendor = vendorUser?.vendors as any;
  
  if (!vendor || vendor.status !== 'Active') {
    redirect('/vendor/dashboard')
  }

  const { data: orders } = await supabase
    .from('orders')
    .select('*')
    .eq('vendor_id', vendor.id)
    .order('created_at', { ascending: false })

  const allOrders = orders || []
  const todayStr  = new Date().toDateString()

  const todayOrders   = allOrders.filter(o => new Date(o.created_at).toDateString() === todayStr)
  const todayRevenue  = todayOrders.reduce((s, o) => s + Number(o.price || 0), 0)
  const totalRevenue  = allOrders.reduce((s, o) => s + Number(o.price || 0), 0)
  const approvedCount = allOrders.filter(o => o.status === 'Approved').length

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4"><div>
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white tracking-tight">Orders</h1>
        <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">All orders generated by your network.</p>
      </div>
        <DateRangeFilter />
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card className="p-5 bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 shadow-sm">
          <p className="text-sm text-gray-500 dark:text-gray-400">Today's Orders</p>
          <p className="text-2xl font-bold text-gray-900 dark:text-white mt-1">{todayOrders.length}</p>
        </Card>
        <Card className="p-5 bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 shadow-sm">
          <p className="text-sm text-gray-500 dark:text-gray-400">Today Revenue</p>
          <p className="text-2xl font-bold text-green-600 mt-1">₹{todayRevenue.toFixed(0)}</p>
        </Card>
        <Card className="p-5 bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 shadow-sm">
          <p className="text-sm text-gray-500 dark:text-gray-400">Total Revenue</p>
          <p className="text-2xl font-bold text-blue-600 mt-1">₹{totalRevenue.toFixed(0)}</p>
        </Card>
        <Card className="p-5 bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 shadow-sm">
          <p className="text-sm text-gray-500 dark:text-gray-400">Approved</p>
          <p className="text-2xl font-bold text-gray-900 dark:text-white mt-1">{approvedCount}</p>
        </Card>
      </div>

      {/* Orders Table */}
      <Card className="overflow-hidden bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 shadow-sm">
        <div className="px-6 py-4 border-b border-gray-100 dark:border-gray-800">
          <h3 className="text-lg font-bold text-gray-900 dark:text-white">Order History</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-gray-500 dark:text-gray-400 uppercase bg-gray-50 dark:bg-gray-900 border-b border-gray-100 dark:border-gray-800">
              <tr>
                <th className="px-6 py-4">Order No.</th>
                <th className="px-6 py-4">Customer</th>
                <th className="px-6 py-4">Product</th>
                <th className="px-6 py-4">Amount</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Date</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {allOrders.length > 0 ? allOrders.map((order: any) => {
                return (
                  <tr key={order.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                    <td className="px-6 py-4">
                      <span className="font-mono text-xs text-gray-600 dark:text-gray-400">
                        {order.order_id}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="font-medium text-gray-900 dark:text-white">{order.customer_name || 'N/A'}</div>
                    </td>
                    <td className="px-6 py-4 text-gray-700 dark:text-gray-300">{order.product_name || '—'}</td>
                    <td className="px-6 py-4 font-semibold text-gray-900 dark:text-white">
                      ₹{Number(order.price).toFixed(2)}
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-medium ${
                        order.status === 'Approved' ? 'bg-green-100 text-green-800' :
                        order.status === 'Rejected' ? 'bg-red-100 text-red-800' :
                        'bg-yellow-100 text-yellow-800'
                      }`}>
                        {order.status === 'Approved' && <CheckCircle2 className="h-3 w-3" />}
                        {order.status === 'Pending'  && <Clock className="h-3 w-3" />}
                        {order.status === 'Rejected' && <XCircle className="h-3 w-3" />}
                        {order.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-xs text-gray-500">
                      {new Date(order.created_at).toLocaleDateString()}
                    </td>
                  </tr>
                )
              }) : (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-gray-500">
                    <ShoppingCart className="h-10 w-10 text-gray-300 mx-auto mb-3" />
                    No orders found in your network.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </Card>
    </div>
  )
}
